            // never a passive re-read elsewhere. Computed once here for both branches below.
            // PR #357 round-10 (finding 1): same treatment for the resolved DURATION, against the
            // CURRENT DefaultDuration — an explicit Update is likewise the one place allowed to move
            // a still-queued toast's persistence forward.
            var newPos = ResolvePosition(options.Position);
            var newDuration = options.Duration ?? DefaultDuration;

