            // its OWN and is at cap, reconciling it first can start an unrelated eviction and await
            // out its ~220ms exit before the destination — which may have had room immediately — ever
            // gets a chance to admit the retargeted entry. Reconciling `newPos` first closes that
            // window exactly like the mounted path does.
            if (newPos != oldPos.Value) await ReconcileGroup(newPos);
            await ReconcileGroup(oldPos.Value);
            return;
