        // — ReconcileGroup wouldn't have rendered anything on its own then — and is a harmless
        // no-op extra render otherwise (ReconcileGroup already committed the consistent state above).
        StateHasChanged();
    }

    // Replaces `_toasts[index]` with the updated options and resets its auto-dismiss timer. Used by
    // every HandleUpdateAsync mutated-toast path (group/persistence-changing or not) so the same
    // logic applies regardless of whether a reconciliation follows. PR #357 round-9 (finding 1/6):
    // `resolvedPosition`/`resolvedPersistent` are supplied by the caller (computed once, at this
    // exact explicit-Update instant) and frozen onto the replacement ToastItem — the same
    // admission-snapshot contract MountToast follows, just for the "explicit Update re-resolves"
    // path instead of first admission.
    private void ApplyToastMutation(
        int index, string toastId, ToastOptions options,
        ToastViewport.ToastPosition resolvedPosition, bool resolvedPersistent)
    {
        _toasts[index] = new ToastItem(toastId, options, resolvedPosition, resolvedPersistent);
        CancelTimer(toastId);
        var duration = options.Duration ?? DefaultDuration;
        if (duration > 0)
        {
            // Routes through StartOrPauseTimer (finding — Codex), not StartTimer directly:
            // CancelTimer above just cleared _pauseReasons, so an unconditional StartTimer here
            // would silently un-pause a toast whose group is still expanded (e.g. a loading toast
            // resolving to a finite duration while the user is still hovering its stack) — same gap
            // as MountToast's, just on the "reset an already-mounted toast's timer" path instead of
            // fresh admission. See the _expandedGroups field comment.
            StartOrPauseTimer(toastId, duration, resolvedPosition);
        }
    }

    private void StartTimer(string id, int duration)
    {
        var cts = new CancellationTokenSource();
        _timers[id] = cts;
        _timerStart[id] = DateTime.UtcNow;
        _timerRemaining[id] = duration;
        SafeAsyncDispatcher.FireAndForget(InvokeAsync, () => DismissAfterDelayAsync(id, duration, cts.Token), "ToastProvider.DismissAfterDelay");
    }

    // PR #357 (finding — Codex): the entry point every site that (re)starts a toast's auto-dismiss
    // timer must use instead of calling StartTimer directly — MountToast (fresh admission) and
    // ApplyToastMutation (an Update resetting an already-mounted toast's timer). If `pos` is
